import './DatePicker.scss';

import { MaskField } from ':components/MaskField';
import { NewDropdownMenu } from ':components/NewDropdownMenu';
import { Icons } from '@beeline/design-tokens/js/iconfont/icons';
import type { ChangeEvent, MouseEvent } from 'react';
import React, { forwardRef, useEffect, useImperativeHandle, useRef } from 'react';

import { classNames } from '../../helpers/classnames';
import { IconButton } from '../IconButton';
import { TextField } from '../TextField';
import { Calendar } from './Calendar';
import { parseDateOnly, parseWithTimeZone } from './convertor';
import type { DatePickerProps } from './DatePicker.types';
import { useDatePicker } from './useDatePicker';
import { maskConfig as defaultMaskConfig, maskConfigTime, maskDateTime, RU_FORMAT_PATTERN_F } from './utils';

export const DatePicker = forwardRef<HTMLInputElement, DatePickerProps>(
	(
		{
			className,
			value = '',
			minDate = '',
			maxDate = '',
			disabled = false,
			dataTestId = 'DatePicker',
			onFocus,
			onChange,
			onBlur,
			onClose,
			onOpen,
			fullWidth,
			mobileView,
			onSaveClick,
			excludeDate,
			customViewDate,
			initialViewDate,
			holidaysDate,
			customizeDay,
			error,
			enableTimePicker = false,
			timeRange = ['00:00', '23:59'],
			outOfRangeErrorText,
			dropdownClassName,
			enableImaskConfig = false,
			maskConfig,
			overlayScroll = true,
			shouldRenderOverlay,
			overlayClassName,
			alignDropDown,
			timeZone,
			hideDropDown = false,
			showAdjacentMonthDays,
			allowAdjacentMonthSelection,
			clearOnExcludedDateClose = true,
			datepickerRef: externalDatepickerRef,
			...restProps
		},
		forwardedRef,
	) => {
		const internalDatepickerRef = useRef<HTMLDivElement>(null);
		const datepickerRef = externalDatepickerRef || internalDatepickerRef;

		const inputRef = useRef<HTMLInputElement>(null);

		useImperativeHandle(forwardedRef, () => inputRef.current);

		const effectiveTimeZone = timeZone || Intl.DateTimeFormat().resolvedOptions().timeZone;

		const {
			isOpen,
			open,
			close,
			selectDate,
			setIsOpen,
			inputValue,
			setInputValue,
			handleChange,
			handleInputFocus,
			dropdownMenuProps,
			handleInputBlur,
		} = useDatePicker({
			value,
			onChange,
			onOpen,
			onFocus,
			onClose,
			onSaveClick,
			mode: 'single',
			enableTimePicker,
			timeZone,
			datepickerRef,
			mobileView,
			dropdownClassName,
			onBlur,
			overlayScroll,
			shouldRenderOverlay,
			overlayClassName,
			alignDropDown,
		});

		const ignoredFirstEmptyAcceptRef = useRef(false);

		// Если открыто, а вдруг disabled => закрыть
		useEffect(() => {
			if (isOpen && disabled) {
				close();
			}
		}, [disabled, close, isOpen]);

		/* Обработчик простого onChange (без IMask) */
		const handleInputChange = (event: ChangeEvent<HTMLInputElement>) => {
			const text = event.target.value;

			if (!text.trim()) {
				setInputValue('');
				handleChange('');
				return;
			}

			// может, не нуна здесь маска совсем? только на длинну?
			// но не удобно же вводить ее, лучше совсем без нее
			const tryMaskStringToDate = maskDateTime(text, enableTimePicker);
			setInputValue(tryMaskStringToDate);

			const isValidDate = RU_FORMAT_PATTERN_F(enableTimePicker).test(text);

			if (!isValidDate) {
				return;
			}

			// обрабатываем дату + время
			if (enableTimePicker) {
				const isoStr = parseWithTimeZone(text, effectiveTimeZone);
				if (!isoStr) {
					handleChange('');
					return;
				}
				handleChange(isoStr);
				return;
			}

			// обрабатываем только дату
			const parsed = parseDateOnly(text);
			if (!parsed) {
				handleChange('');
				return;
			}

			handleChange(parsed);
		};

		/* Обработчик IMask: работает и как onComplete, и как onChange */
		const handleMaskComplete = (maskedVal: string, _second: any, _event?: InputEvent) => {
			const normalizedMaskedVal = maskedVal.trim();
			setInputValue(normalizedMaskedVal);

			// Для onChange (accept) вторым параметром приходит unmaskedValue (string)
			const unmaskedVal = typeof _second === 'string' ? _second : undefined;
			const normalizedUnmaskedVal = typeof unmaskedVal === 'string' ? unmaskedVal.trim() : undefined;

			// Полная очистка пользователем — сбрасываем value
			if ((typeof normalizedUnmaskedVal === 'string' && normalizedUnmaskedVal.length === 0) || !normalizedMaskedVal) {
				handleChange('');
				return;
			}

			// При частично заполненной маске не трогаем value (оставляем предыдущее корректное значение)
			const isValidDate = RU_FORMAT_PATTERN_F(enableTimePicker).test(normalizedMaskedVal);
			if (!isValidDate) {
				return;
			}

			if (enableTimePicker) {
				const isoStr = parseWithTimeZone(normalizedMaskedVal, effectiveTimeZone);
				if (!isoStr) {
					handleChange('');
					return;
				}
				handleChange(isoStr);
				return;
			}

			const parsed = parseDateOnly(normalizedMaskedVal);
			if (!parsed) {
				handleChange('');
				return;
			}

			handleChange(parsed);
		};

		const handleCalendarIconClick = (event: MouseEvent<HTMLElement>) => {
			event.stopPropagation();
			isOpen ? close() : open();
		};

		/* Кнопка "Сохранить", если есть onSaveClick (логика в шаблоне)*/
		const onSave = (): void => {
			onSaveClick?.();
			close();
		};

		/* Закрытие дропдауна => проверка excludeDate */
		const handleCloseDropdown = () => {
			if (!inputValue || typeof inputValue !== 'string') {
				return;
			}

			if (enableTimePicker) {
				const isoStr = parseWithTimeZone(inputValue, effectiveTimeZone);
				if (!isoStr) {
					return;
				}
				const dateObj = new Date(isoStr);
				if (clearOnExcludedDateClose && excludeDate?.(dateObj)) {
					setInputValue('');
					handleChange('');
				}
				return;
			}

			const parsed = parseDateOnly(inputValue);
			if (!parsed) {
				return;
			}
			const [yyyy, mm, dd] = parsed.split('-');
			const dateObj = new Date(+yyyy, +mm - 1, +dd);
			if (clearOnExcludedDateClose && excludeDate?.(dateObj)) {
				setInputValue('');
				handleChange('');
			}
		};

		const rightIcon = (
			<IconButton
				size="medium"
				iconName={Icons.Calendar}
				onClick={disabled ? undefined : handleCalendarIconClick}
				disabled={disabled}
				type="button"
			/>
		);

		return (
			<div
				data-testid={dataTestId}
				ref={datepickerRef}
				className={classNames('dsb_datepicker', fullWidth && 'dsb_datepicker__full-width', className)}
				data-test-id={dataTestId}
			>
				{enableImaskConfig ? (
					<MaskField
						{...restProps}
						ref={inputRef}
						value={inputValue}
						disabled={disabled}
						endAdornment={rightIcon}
						className="dsb_datepicker_input-mask"
						onBlur={handleInputBlur}
						onFocus={handleInputFocus}
						onChange={handleMaskComplete}
						onComplete={handleMaskComplete}
						fullWidth={fullWidth}
						error={error}
						maskConfig={maskConfig || (enableTimePicker ? maskConfigTime : defaultMaskConfig)}
					/>
				) : (
					<TextField
						{...restProps}
						ref={inputRef}
						value={inputValue}
						disabled={disabled}
						endAdornment={rightIcon}
						className="dsb_datepicker_input-textfield"
						onBlur={handleInputBlur}
						onFocus={handleInputFocus}
						onChange={handleInputChange}
						fullWidth={fullWidth}
						error={error}
					/>
				)}

				{isOpen && !hideDropDown && (
					<NewDropdownMenu {...dropdownMenuProps} onClose={handleCloseDropdown}>
						<Calendar
							value={value}
							minValue={minDate}
							maxValue={maxDate}
							datepickerRef={datepickerRef}
							onSelectDate={selectDate}
							onSaveClick={onSaveClick ? onSave : null}
							dataTestId={`${dataTestId}-calendar`}
							mobileView={mobileView}
							onOutsideClick={mobileView ? close : undefined}
							excludeDate={excludeDate}
							customViewDate={customViewDate}
							initialViewDate={initialViewDate}
							holidaysDate={holidaysDate}
							enableTimePicker={enableTimePicker}
							timeRange={timeRange}
							outOfRangeErrorText={outOfRangeErrorText}
							outputDateFormat={enableTimePicker ? "yyyy-MM-dd'T'HH:mm:ss'Z'" : 'yyyy-MM-dd'}
							timeZone={effectiveTimeZone}
							customizeDay={customizeDay}
							showAdjacentMonthDays={showAdjacentMonthDays}
							allowAdjacentMonthSelection={allowAdjacentMonthSelection}
						/>
					</NewDropdownMenu>
				)}
			</div>
		);
	},
);
